#!/usr/bin/env bash
set -euo pipefail

# Freddy Fix It — Recurring Booking + Prepay installer (SUPERSET).
# Adds category-aware recurrence cadences (weekly..annual + per-km for vehicle
# jobs) and an optional "prepay N visits" escrow pool that is held securely and
# released to the pro one visit at a time. Includes everything from the earlier
# milestone-escrow installer, so running THIS one delivers all prior work too.
# DB + edge-function DEPLOYS are already LIVE (via Supabase MCP); this ships the
# FRONTEND plus committed copies of the edge-function source for version control.
# Resets to published origin/main first, so it is a full superset.

TARGET="$HOME/Desktop/freddy-fixit"
if [ ! -d "$TARGET/.git" ]; then echo "❌ $TARGET is not a git repo"; exit 1; fi
cd "$TARGET"
echo "→ Syncing to the published version (discards any half-applied local state)"
git fetch origin --quiet || true
git reset --hard origin/main --quiet
rm -f .github/workflows/typecheck.yml
echo "→ Writing files into $TARGET"

write_file() {  # write_file <destpath> ; base64 body on stdin
  local dest="$1"
  mkdir -p "$(dirname "$dest")"
  base64 --decode > "$dest"
}

